    "# ═══════ KHÔNG SAMPLING — SỬ DỤNG TOÀN BỘ DỮ LIỆU ═══════\n",
    "SAMPLES_PER_MONTH = None  # None = toàn bộ dữ liệu LAMDA, không lấy mẫu\n",
    "\n",
    "TRAINING_WINDOW = 12\n",
    "TESTING_WINDOW = 1\n",
    "GRANULARITY = \"month\"\n",
    "\n",
    "# ═══════ 1 SEED trước để thăm dò RAM, nếu OK tăng lên 3 ═══════\n",
    "SEEDS = [0]\n",
    "\n",
    "# ═══════ BUDGET GRID (Cặp ngân sách chạy chéo song hành) ═══════\n",
    "from itertools import product\n",
    "AL_RATES = [0, 50, 100, 200, 400]\n",
    "REJ_RATES = [0, 50, 100, 200, 400]\n",
    "BUDGET_PAIRS = list(product(AL_RATES, REJ_RATES))\n",
    "print(f\" Full grid: {len(BUDGET_PAIRS)} tổ hợp AL × Rej × {len(SEEDS)} seeds = {len(BUDGET_PAIRS) * len(SEEDS)} runs\")\n",
