    "\n",
    "SUPERVISED_MODELS = [\"Drebin-LinearSVC\"]\n",
    "\n",
    "# ═══════ CHỈ CHẠY DRMD-mp1 (Baseline đối xứng) ═══════\n",
    "DRMD_ABLATIONS = [\n",
    "    {\n",
    "        \"name\": \"DRMD-mp1\",\n",
    "        \"model\": \"PPO_Bandit\",\n",
    "        \"minority_priority\": 1,\n",
