    "        \"fn_penalty\": 1.0,         # Mặc định (đối xứng)\n",
    "    }\n",
    "]\n",
    "\n",
    "WORK = Path(\"/kaggle/working\")\n",
    "OUT = WORK / \"results\" / EXPERIMENT_NAME\n",
    "DATA_OUT = WORK / \"DRMD_datasets\" / EXPERIMENT_NAME\n",
    "RAW_OUT = OUT / \"raw\"\n",
    "TABLE_OUT = OUT / \"tables\"\n",
    "FIG_OUT = OUT / \"figures\"\n",
    "\n",
    "for p in [OUT, DATA_OUT, RAW_OUT, TABLE_OUT, FIG_OUT]:\n",
    "    p.mkdir(parents=True, exist_ok=True)\n",
    "\n",
    "print(\"EXPERIMENT_NAME:\", EXPERIMENT_NAME)\n",
    "print(\"DATASET_YEARS:\", DATASET_YEARS)\n",
    "print(\"SAMPLES_PER_MONTH:\", SAMPLES_PER_MONTH, \"(None = FULL DATA)\")\n",
    "print(\"SEEDS:\", SEEDS)\n",
    "print(\"BUDGET_PAIRS:\", BUDGET_PAIRS)"
